const execution = $input.first().json.execution;
const workflow = $input.first().json.workflow;

// Define the logic to fix the URL
const rawUrl = execution?.url || '';
// This removes ":5678" from the string
const fixedUrl = rawUrl.replace(':5678', ''); 

return [{
  json: {
    execution: {
      id: execution?.id || '',
      url: fixedUrl,  // <--- Updated to use the fixed URL
      retryOf: "0",
      establishedAt: execution?.executionContext?.establishedAt || '',
      error: {
        message: execution?.error?.message || '',
        stack: execution?.error?.stack || ''
      },
      lastNodeExecuted: execution?.lastNodeExecuted || '',
      mode: execution?.mode || ''
    },
    workflow: {
      id: workflow?.id || '',
      name: workflow?.name || ''
    }
  }
}];

