// n8n Code Node - Format AI Agent Output (Text Only Status)

const item = $input.item.json;

function formatOutput(outputText) {
  function extractSection(text, sectionName, nextSectionName = null) {
    const pattern = nextSectionName 
      ? `\\*\\*${sectionName}\\*\\*\\n(.+?)(?=\\n\\*\\*${nextSectionName})`
      : `\\*\\*${sectionName}\\*\\*\\n(.+?)(?=\\n---|$)`;
    const regex = new RegExp(pattern, 's');
    const match = text.match(regex);
    return match ? match[1].trim() : "";
  }

  const errorMessage = outputText.match(/Message:\s*(.+?)(?:\n|$)/)?.[1]?.trim() || "";
  const component = outputText.match(/Component:\s*(.+?)(?:\n|$)/)?.[1]?.trim() || "";
  const location = outputText.match(/Location:\s*(.+?)(?:\n|$)/)?.[1]?.trim() || "";

  const summary = extractSection(outputText, "SUMMARY", "ROOT CAUSE");
  const rootCause = extractSection(outputText, "ROOT CAUSE", "RESOLUTION");
  const resolution = extractSection(outputText, "RESOLUTION", "CONTEXT");
  const context = extractSection(outputText, "CONTEXT", "CONFIDENCE");
  const confidence = extractSection(outputText, "CONFIDENCE");

  const kbStatusMatch = outputText.match(/---\n([\s\S]+?)$/);

  let pastSolutionFoundBool = false;
  let kbStatus = "No similar error found. This is the first occurrence of this error in the knowledge base. The solution above is based on stack trace analysis and external research.";
  let previousIncidentDate = null;

  if (kbStatusMatch) {
    const statusText = kbStatusMatch[1].trim();

    pastSolutionFoundBool =
      statusText.includes("✓") ||
      statusText.toLowerCase().includes("similar error found");

    let cleanStatus = statusText
      .replace(/✓/g, '')
      .replace(/⚠/g, '')
      .replace(/SIMILAR ERROR FOUND/g, 'Similar error found')
      .replace(/NO SIMILAR ERROR FOUND/g, 'No similar error found')
      .trim();

    kbStatus = cleanStatus;

    const dateMatch = statusText.match(/Previous incident:\s*(.+?)(?:\n|$)/);
    if (dateMatch) {
      previousIncidentDate = dateMatch[1].trim();
    }
  }

  return {
    timestamp: new Date().toISOString(),
    error_analysis: {
      error_context: {
        message: errorMessage,
        component: component,
        location: location
      },
      summary,
      root_cause: rootCause,
      resolution,
      context,
      confidence,
      knowledge_base: {
        past_solution_found: pastSolutionFoundBool ? "Yes" : "No",
        status: kbStatus,
        previous_incident_date: previousIncidentDate
      }
    }
  };
}

const outputText = item.output;
const formattedData = formatOutput(outputText);

return { json: formattedData };
